-- ============================================
-- Legislacao full-site: nikolas-ferreira / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/209787
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = nikolas-ferreira-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 116 rows Camara legacy existentes, somente 103
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=209787, tipo Deputado(a), ordemAssinatura=1.
-- 13 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'nikolas-ferreira';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'nikolas-ferreira: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 116 THEN
    RAISE EXCEPTION 'Pre-condicao nikolas-ferreira: esperadas 116 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2602905', '2602122', '2609978', '2609897', '2609896', '2609895', '2609894', '2609893', '2609401', '2609025', '2609016', '2608253', '2601036', '2597565', '2596952', '2596692', '2587868', '2587037', '2586975', '2581552', '2581543', '2578097', '2578057', '2597144', '2596951', '2587872', '2587867', '2587036', '2586757', '2581550', '2581541', '2578971', '2578095', '2578047', '2602939', '2602833', '2598595', '2596977', '2596950', '2595309', '2589467', '2587863', '2587004', '2586706', '2581549', '2581538', '2578104', '2578076', '2577919', '2602929', '2602667', '2596955', '2596949', '2593945', '2589318', '2587870', '2587431', '2587003', '2581546', '2581041', '2578101', '2578064', '2597566', '2593106', '2589317', '2587869', '2587002', '2581545', '2579925', '2578099', '2578061', '2604363', '2617346', '2615934', '2616121', '2615463', '2606913', '2616035', '2613074', '2607631', '2606912', '2606909', '2606899', '2606892', '2606745', '2605392', '2596948', '2617891', '2617890', '2618469', '2605395', '2602909', '2587090', '2613091', '2606627', '2602906', '2596954', '2589469', '2613516', '2613515', '2613464', '2613459', '2614411');
  IF target_present <> 103 THEN
    RAISE EXCEPTION 'Pre-condicao nikolas-ferreira: esperadas 103 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2602905', '2602122', '2609978', '2609897', '2609896', '2609895', '2609894', '2609893', '2609401', '2609025', '2609016', '2608253', '2601036', '2597565', '2596952', '2596692', '2587868', '2587037', '2586975', '2581552', '2581543', '2578097', '2578057', '2597144', '2596951', '2587872', '2587867', '2587036', '2586757', '2581550', '2581541', '2578971', '2578095', '2578047', '2602939', '2602833', '2598595', '2596977', '2596950', '2595309', '2589467', '2587863', '2587004', '2586706', '2581549', '2581538', '2578104', '2578076', '2577919', '2602929', '2602667', '2596955', '2596949', '2593945', '2589318', '2587870', '2587431', '2587003', '2581546', '2581041', '2578101', '2578064', '2597566', '2593106', '2589317', '2587869', '2587002', '2581545', '2579925', '2578099', '2578061', '2604363', '2617346', '2615934', '2616121', '2615463', '2606913', '2616035', '2613074', '2607631', '2606912', '2606909', '2606899', '2606892', '2606745', '2605392', '2596948', '2617891', '2617890', '2618469', '2605395', '2602909', '2587090', '2613091', '2606627', '2602906', '2596954', '2589469', '2613516', '2613515', '2613464', '2613459', '2614411')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'nikolas-ferreira-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao nikolas-ferreira: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao nikolas-ferreira: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

